arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_5eea1d2d00f148469b71ab9cd12ba82e.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(section == _activeSection ? "active" : "")"
                            @onclick="() => SetActiveSection(section)">
                        <span class="section-icon">@GetSectionIcon(section)</span>
                        @section
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_activeSection == "Profile")
        {
            <ProfileSection SettingsService="SettingsService" />
        }
        else if (_activeSection == "Notifications")
        {
            <NotificationsSection SettingsService="SettingsService" />
        }
        else if (_activeSection == "Security")
        {
            <SecuritySection SettingsService="SettingsService" />
        }
        else if (_activeSection == "Appearance")
        {
            <AppearanceSection SettingsService="SettingsService" />
        }
    </div>
</div>

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    private void SetActiveSection(string section) => _activeSection = section;

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-dashboard {
    display: flex;
    min-height: 80vh;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
    padding-bottom: 0.75rem;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.65rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

.section-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

