arguments.file_text:
@using sv_5eea1d2d00f148469b71ab9cd12ba82e.Services

<h4 class="mb-4">Profile</h4>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    <div class="row g-4">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <label class="form-label fw-semibold d-block">Avatar Preview</label>
            <div class="avatar-preview mb-2">
                <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" width="120" height="120" />
            </div>
            <div class="mb-3">
                <input type="text" class="form-control form-control-sm" @bind="_avatarUrl"
                       placeholder="Avatar URL" />
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            <span>✅ @_successMessage</span>
            <button type="button" class="btn-close ms-auto" @onclick="() => _successMessage = null"></button>
        </div>
    }
}

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Snapshot of last-saved state for discard.
    private UserProfile _savedSnapshot = default!;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedSnapshot = profile;
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedSnapshot = profile;
        _successMessage = "Profile saved successfully.";
        _saving = false;
    }

    private void Discard()
    {
        ApplyProfile(_savedSnapshot);
        _successMessage = null;
    }
}

@using sv_5eea1d2d00f148469b71ab9cd12ba82e.Services

<h4 class="mb-4">Notifications</h4>

@if (_loading)
{
    <p class="text-muted">Loading preferences…</p>
}
else
{
    <div class="mb-4">
        <h6 class="fw-semibold mb-3">General</h6>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6 class="fw-semibold mb-3">Muted Channels</h6>
        @foreach (var channel in _allChannels)
        {
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="ch-@channel"
                       checked="@_mutedChannels.Contains(channel)"
                       @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="ch-@channel">
                    #@channel @(_mutedChannels.Contains(channel) ? "(muted)" : "")
                </label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            <span>✅ @_successMessage</span>
            <button type="button" class="btn-close ms-auto" @onclick="() => _successMessage = null"></button>
        </div>
    }
}

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];

    // Available channels for the mute list.
    private readonly string[] _allChannels = ["general", "announcements", "random", "engineering", "off-topic"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _successMessage = "Notification preferences saved.";
        _saving = false;
    }
}

@using sv_5eea1d2d00f148469b71ab9cd12ba82e.Services

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    @* ── Change Password ── *@
    <div class="card mb-4">
        <div class="card-header d-flex align-items-center justify-content-between"
             role="button" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span class="fw-semibold">Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>

                @if (_passwordError is not null)
                {
                    <div class="alert alert-danger py-2">@_passwordError</div>
                }
                @if (_passwordSuccess is not null)
                {
                    <div class="alert alert-success py-2">@_passwordSuccess</div>
                }

                <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @(_changingPassword ? "Updating…" : "Update Password")
                </button>
            </div>
        }
    </div>

    @* ── Two-Factor Authentication ── *@
    <div class="card mb-4">
        <div class="card-body d-flex align-items-center justify-content-between">
            <div>
                <span class="fw-semibold">Two-Factor Authentication</span>
                <span class="badge ms-2 @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch mb-0">
                <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
            </div>
        </div>
    </div>

    @if (_lastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-4">
            Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy 'at' HH:mm 'UTC'")
        </p>
    }

    @* ── Active Sessions ── *@
    <h5 class="fw-semibold mb-3">Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-hover align-middle">
            <thead class="table-light">
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in _sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td class="text-end">
                            @if (session.Id != _currentSessionId)
                            {
                                @if (_confirmingRevokeId == session.Id)
                                {
                                    <span class="me-2 text-danger small">Revoke this session?</span>
                                    <button class="btn btn-danger btn-sm me-1"
                                            @onclick="() => RevokeSessionAsync(session.Id)"
                                            disabled="@_revoking">
                                        Confirm
                                    </button>
                                    <button class="btn btn-outline-secondary btn-sm"
                                            @onclick="() => _confirmingRevokeId = null">
                                        Cancel
                                    </button>
                                }
                                else
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => _confirmingRevokeId = session.Id">
                                        Revoke
                                    </button>
                                }
                            }
                            else
                            {
                                <span class="badge bg-info">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _loading = true;

    // Password change
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordError;
    private string? _passwordSuccess;

    // 2FA
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;

    // Sessions
    private List<ActiveSession> _sessions = [];
    private string? _confirmingRevokeId;
    private bool _revoking;

    // Treat the first session as the current one for demo purposes.
    private string _currentSessionId = "";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = [.. settings.Sessions];
        _currentSessionId = _sessions.FirstOrDefault()?.Id ?? "";
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordSuccess = "Password updated successfully.";
            _currentPassword = _newPassword = _confirmPassword = "";
            _lastPasswordChange = DateTime.UtcNow;
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        _revoking = true;
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions.RemoveAll(s => s.Id == sessionId);
        _confirmingRevokeId = null;
        _revoking = false;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_5eea1d2d00f148469b71ab9cd12ba82e.Services

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    <div class="row g-4">
        <div class="col-md-7">
            @* ── Theme ── *@
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="theme-@theme">@theme</label>
                    </div>
                }
            </div>

            @* ── Font Size ── *@
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="fs-@size">@size</label>
                    </div>
                }
            </div>

            @* ── Language ── *@
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Language</h6>
                <select class="form-select w-auto" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            @* ── Compact Mode ── *@
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                    <span>✅ @_successMessage</span>
                    <button type="button" class="btn-close ms-auto" @onclick="() => _successMessage = null"></button>
                </div>
            }
        </div>

