toolArgs.file_text:
@using sv_5eea1d2d00f148469b71ab9cd12ba82e.Services

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    <div class="row g-4">
        <div class="col-md-7">
            @* ── Theme ── *@
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="theme-@theme">@theme</label>
                    </div>
                }
            </div>

            @* ── Font Size ── *@
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="fs-@size">@size</label>
                    </div>
                }
            </div>

            @* ── Language ── *@
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Language</h6>
                <select class="form-select w-auto" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            @* ── Compact Mode ── *@
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                    <span>✅ @_successMessage</span>
                    <button type="button" class="btn-close ms-auto" @onclick="() => _successMessage = null"></button>
                </div>
            }
        </div>

        @* ── Live Preview ── *@
        <div class="col-md-5">
            <h6 class="fw-semibold mb-2">Live Preview</h6>
            <div class="preview-panel @PreviewThemeClass" style="font-size: @PreviewFontSize;">
                <div class="preview-header">
                    <strong>Dashboard</strong>
                </div>
                <div class="preview-body @(_compactMode ? "compact" : "")">
                    <p class="mb-1">Welcome back! Here's your overview.</p>
                    <div class="preview-card">
                        <span>📊 Reports</span>
                        <span class="text-muted small">3 new</span>
                    </div>
                    <div class="preview-card">
                        <span>💬 Messages</span>
                        <span class="text-muted small">12 unread</span>
                    </div>
                </div>
                <div class="preview-footer text-muted small">
                    Theme: @_theme · Font: @_fontSize · Lang: @_language @(_compactMode ? "· Compact" : "")
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese"];

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _successMessage = "Appearance settings saved.";
        _saving = false;
    }
}

.preview-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-body.compact {
    padding: 0.5rem 1rem;
}

.preview-body.compact p {
    margin-bottom: 0.25rem !important;
}

.preview-body.compact .preview-card {
    padding: 0.35rem 0.6rem;
    margin-bottom: 0.25rem;
}

.preview-card {
    display: flex;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 0.5rem;
}

.preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
}

/* Light theme (default) */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

/* Dark theme */
.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-dark .preview-card {
    border-color: #45475a;
    background: #313244;
}

.preview-dark .preview-footer {
    border-color: #45475a;
    color: #a6adc8;
}

.preview-dark .text-muted {
